struct half2 {
  uint16_t x;
  uint16_t y;
};

static inline float half_to_float(uint16_t h) {
  const uint32_t sign = (static_cast<uint32_t>(h & 0x8000)) << 16;
  uint32_t exp = (h >> 10) & 0x1f;
  uint32_t mant = h & 0x03ff;
  uint32_t bits;

  if (exp == 0) {
    if (mant == 0) {
      bits = sign;
    } else {
      exp = 127 - 15 + 1;
      while ((mant & 0x0400) == 0) {
        mant <<= 1;
        --exp;
      }
      mant &= 0x03ff;
      bits = sign | (exp << 23) | (mant << 13);
    }
  } else if (exp == 0x1f) {
    bits = sign | 0x7f800000u | (mant << 13);
  } else {
    bits = sign | ((exp + (127 - 15)) << 23) | (mant << 13);
  }

  float out;
  std::memcpy(&out, &bits, sizeof(out));
  return out;
}

static inline uint16_t float_to_half(float f) {
  uint32_t bits;
  std::memcpy(&bits, &f, sizeof(bits));

  const uint32_t sign = (bits >> 16) & 0x8000u;
  const uint32_t exp = (bits >> 23) & 0xffu;
  const uint32_t mant = bits & 0x007fffffu;

  if (exp == 0xffu) {
    if (mant != 0) return static_cast<uint16_t>(sign | 0x7e00u);
    return static_cast<uint16_t>(sign | 0x7c00u);
  }

  int new_exp = static_cast<int>(exp) - 127 + 15;
  if (new_exp >= 31) {
    return static_cast<uint16_t>(sign | 0x7c00u);
  }

  if (new_exp <= 0) {
    if (new_exp < -10) return static_cast<uint16_t>(sign);
    uint32_t new_mant = mant | 0x00800000u;
    const int shift = 14 - new_exp;
    uint32_t rounded = new_mant >> shift;
    if ((new_mant >> (shift - 1)) & 1u) rounded += 1u;
    return static_cast<uint16_t>(sign | rounded);
  }

  uint32_t rounded_mant = mant + 0x00001000u;
  if (rounded_mant & 0x00800000u) {
    rounded_mant = 0;
    ++new_exp;
    if (new_exp >= 31) return static_cast<uint16_t>(sign | 0x7c00u);
  }

  return static_cast<uint16_t>(sign | (static_cast<uint32_t>(new_exp) << 10) |
                               (rounded_mant >> 13));
}

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <class T>
inline bool equal(const T a, const T b) {
  return a == b;
}

template <>
inline int mad(const int a, const int b, const int c) {
  const uint32_t ua = static_cast<uint32_t>(a);
  const uint32_t ub = static_cast<uint32_t>(b);
  const uint32_t uc = static_cast<uint32_t>(c);
  const uint32_t ur = ua * ub + uc;
  return static_cast<int32_t>(ur);
}

template <>
inline half2 conv_int(const int i) {
  const uint16_t h = float_to_half(static_cast<float>(i));
  return half2{h, h};
}

template <>
inline half2 mad(const half2 a, const half2 b, const half2 c) {
  const float ax = half_to_float(a.x);
  const float ay = half_to_float(a.y);
  const float bx = half_to_float(b.x);
  const float by = half_to_float(b.y);
  const float cx = half_to_float(c.x);
  const float cy = half_to_float(c.y);
  return half2{float_to_half(ax * bx + cx), float_to_half(ay * by + cy)};
}

template <>
inline bool equal(const half2 a, const half2 b) {
  return a.x == b.x && a.y == b.y;
}

template <class T, int blockdim, unsigned int granularity,
          unsigned int fusion_degree, unsigned int compute_iterations,
          bool TemperateUnroll>
static void benchmark_func(T seed, T* g_data, int total_blocks) {
  (void)TemperateUnroll;
  const unsigned int blockSize = blockdim;
  const long long total_threads = static_cast<long long>(total_blocks) * blockSize;
  const long long stride = blockSize;
  const long long big_stride =
      static_cast<long long>(total_blocks) * blockSize * granularity;

#pragma omp parallel for schedule(static)
  for (long long tid = 0; tid < total_threads; ++tid) {
    const long long blockIdx = tid / blockSize;
    const long long threadIdx = tid % blockSize;
    const long long idx = blockIdx * blockSize * granularity + threadIdx;

    T tmps[granularity];
    for (unsigned int k = 0; k < fusion_degree; ++k) {
      for (unsigned int j = 0; j < granularity; ++j) {
        tmps[j] = g_data[idx + static_cast<long long>(j) * stride +
                         static_cast<long long>(k) * big_stride];
        for (unsigned int i = 0; i < compute_iterations; ++i) {
          tmps[j] = mad(tmps[j], tmps[j], seed);
        }
      }

      T sum = conv_int<T>(0);
      for (unsigned int j = 0; j < granularity; j += 2) {
        sum = mad(tmps[j], tmps[j + 1], sum);
      }

      if (equal(sum, conv_int<T>(-1))) {
        g_data[idx + static_cast<long long>(k) * big_stride] = sum;
      }
    }
  }
}

template <class F>
static float time_ms(F&& f) {
  const auto start = std::chrono::high_resolution_clock::now();
  f();
  const auto stop = std::chrono::high_resolution_clock::now();
  return std::chrono::duration<float, std::milli>(stop - start).count();
}

static void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
  const int TOTAL_REDUCED_BLOCKS = static_cast<int>(reduced_grid_size / BLOCK_SIZE);
  if (TOTAL_REDUCED_BLOCKS <= 0) return;
  benchmark_func<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true>(
      static_cast<short>(1), reinterpret_cast<short*>(cd), TOTAL_REDUCED_BLOCKS);
}

template <unsigned int compute_iterations>
static void runbench(double* cd, long size, bool doHalfs) {
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const int BLOCK_SIZE = 256;
  const int TOTAL_BLOCKS = static_cast<int>(compute_grid_size / BLOCK_SIZE);
  const long long computations =
      (ELEMENTS_PER_THREAD * static_cast<long long>(compute_grid_size) +
       (2LL * ELEMENTS_PER_THREAD * compute_iterations) *
           static_cast<long long>(compute_grid_size)) *
      FUSION_DEGREE;
  const long long memoryoperations = size;

  float kernel_time_mad_sp = time_ms([&] {
    if (TOTAL_BLOCKS > 0) {
      benchmark_func<float, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, false>(1.0f, reinterpret_cast<float*>(cd),
                                                TOTAL_BLOCKS);
    }
  });

  float kernel_time_mad_dp = time_ms([&] {
    if (TOTAL_BLOCKS > 0) {
      benchmark_func<double, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, false>(1.0, cd, TOTAL_BLOCKS);
    }
  });

  float kernel_time_mad_hp = 0.f;
  if (doHalfs) {
    kernel_time_mad_hp = time_ms([&] {
      if (TOTAL_BLOCKS > 0) {
        benchmark_func<half2, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                       compute_iterations, false>(conv_int<half2>(1),
                                                  reinterpret_cast<half2*>(cd),
                                                  TOTAL_BLOCKS);
      }
    });
  }

  float kernel_time_mad_int = time_ms([&] {
    if (TOTAL_BLOCKS > 0) {
      benchmark_func<int, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, true>(1, reinterpret_cast<int*>(cd),
                                               TOTAL_BLOCKS);
    }
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(half2)) / kernel_time_mad_hp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

